INSERT INTO clinlims.dictionary_category (id, name, description, lastupdated)
SELECT nextval('clinlims.dictionary_category_seq'), 'Bacteria', 'Liste des bactéries et organismes', now()
WHERE NOT EXISTS (SELECT 1 FROM clinlims.dictionary_category WHERE name = 'Bacteria');

